import type { AnalysisResult } from '../engine/types';

const BANNER_ID = 'phishguard-warning-banner';

const SHIELD_SVG =
  '<svg width="20" height="20" viewBox="0 0 24 24" fill="none" aria-hidden="true">' +
  '<path d="M12 2.5 4.5 5.4v5.2c0 4.6 3.2 8.2 7.5 9.9 4.3-1.7 7.5-5.3 7.5-9.9V5.4L12 2.5Z" fill="#fff"/>' +
  '<path d="M12 8v4.5" stroke="#b91c1c" stroke-width="2" stroke-linecap="round"/>' +
  '<circle cx="12" cy="16" r="1.1" fill="#b91c1c"/></svg>';

export function removeWarningBanner(): void {
  document.getElementById(BANNER_ID)?.remove();
}

export function showWarningBanner(result: AnalysisResult): void {
  removeWarningBanner();

  const banner = document.createElement('div');
  banner.id = BANNER_ID;
  banner.setAttribute('role', 'alert');
  Object.assign(banner.style, {
    position: 'fixed',
    top: '0', left: '0', right: '0',
    zIndex: '2147483647',
    display: 'flex',
    alignItems: 'center',
    gap: '12px',
    padding: '12px 18px',
    background: '#b91c1c',
    color: '#fff',
    font: '500 13.5px/1.45 ui-sans-serif, system-ui, -apple-system, "Segoe UI", Roboto, sans-serif',
    boxShadow: '0 2px 12px rgba(0,0,0,.28)',
  });

  const icon = document.createElement('span');
  icon.style.flex = 'none';
  icon.style.display = 'inline-flex';
  icon.innerHTML = SHIELD_SVG;

  const text = document.createElement('span');
  text.style.flex = '1';
  text.innerHTML =
    `<strong style="font-weight:600">Veladia:</strong> este sitio muestra señales de phishing ` +
    `(riesgo ${result.score}/100). No introduzcas contraseñas ni datos personales.`;

  const dismiss = document.createElement('button');
  dismiss.type = 'button';
  dismiss.textContent = 'Entiendo el riesgo';
  Object.assign(dismiss.style, {
    flex: 'none',
    cursor: 'pointer',
    border: '1px solid rgba(255,255,255,.55)',
    background: 'transparent',
    color: '#fff',
    padding: '7px 13px',
    borderRadius: '8px',
    font: 'inherit',
    fontWeight: '600',
  });
  dismiss.addEventListener('click', () => banner.remove());

  banner.append(icon, text, dismiss);
  document.documentElement.appendChild(banner);
}
