import { collectPageContext } from './collect-context';
import { showWarningBanner, removeWarningBanner } from './banner';
import { MESSAGE } from '../shared/messages';
import type { AnalysisResult } from '../engine/types';

let lastUrl = '';

function analyzeCurrentPage(): void {
  const context = collectPageContext();
  try {
    chrome.runtime.sendMessage(
      { type: MESSAGE.ANALYZE_CONTENT, context },
      (response: { result: AnalysisResult | null; showBanner?: boolean } | undefined) => {
        if (chrome.runtime.lastError || !response?.result) return;
        if (response.showBanner && response.result.level === 'dangerous') {
          showWarningBanner(response.result);
        } else {
          removeWarningBanner();
        }
      },
    );
  } catch {
    /* contexto de la extensión invalidado (p. ej. tras recargarla) */
  }
}

function onNavigation(): void {
  if (location.href === lastUrl) return;
  lastUrl = location.href;
  removeWarningBanner();
  analyzeCurrentPage();
}

/** Reacciona a la navegación de SPAs (History API) además de la carga inicial. */
function installSpaHooks(): void {
  const fire = () => window.dispatchEvent(new Event('phishguard:locationchange'));
  for (const method of ['pushState', 'replaceState'] as const) {
    const original = history[method];
    history[method] = function (this: History, ...args: Parameters<History['pushState']>) {
      const result = original.apply(this, args);
      fire();
      return result;
    };
  }
  window.addEventListener('popstate', fire);

  let scheduled = false;
  window.addEventListener('phishguard:locationchange', () => {
    if (scheduled) return;
    scheduled = true;
    setTimeout(() => {
      scheduled = false;
      onNavigation();
    }, 350);
  });
}

function start(): void {
  lastUrl = location.href;
  installSpaHooks();
  analyzeCurrentPage();
}

if (document.readyState === 'complete') {
  start();
} else {
  window.addEventListener('load', start, { once: true });
}
